import{c as t}from"./api-RY2-2DBj.js";const s={getAll(){return t.get("/roomtransfers")},getById(r){return t.get(`/roomtransfers/${r}`)},getByContractId(r){return t.get(`/roomtransfers/contract/${r}`)},getByStudentId(r){return t.get(`/roomtransfers/student/${r}`)},getByStatus(r){return t.get(`/roomtransfers/status/${r}`)},create(r){return t.post("/roomtransfers",r)},update(r,e){return t.put(`/roomtransfers/${r}`,e)},approve(r,e){return t.put(`/roomtransfers/${r}/approve`,e)},reject(r,e){return t.put(`/roomtransfers/${r}/reject`,e)},delete(r){return t.delete(`/roomtransfers/${r}`)}};export{s as r};
